/**
 * On-device inference service.
 *
 * Real implementation backed by `llama.rn`. Loads Antoine's GGUF model
 * file, builds the message array with the system prompt, runs completion
 * on-device, and streams tokens to an optional callback.
 *
 * Public API surface is preserved from the prior stub so callers
 * (`useAntoine`) only change to pass a real path and a streaming callback.
 *
 * Privacy invariant (CLAUDE.md, wiki/concepts/privacy-invariant.md):
 *   This file makes ZERO remote requests. The model is loaded from local
 *   disk; tokens are generated by `llama.rn` running natively. No remote
 *   transport of any kind is permitted here.
 *   CI verifies this — see wiki/concepts/privacy-invariant.md for the
 *   exact grep used in code review. It must return zero matches against
 *   this file.
 */
import {
  initLlama as nativeInitLlama,
  type LlamaContext as NativeLlamaContext,
  releaseAllLlama as nativeReleaseAll,
  type TokenData,
} from 'llama.rn';

import { ANTOINE_SYSTEM_PROMPT } from '@/constants/antoine';
import type { InferenceMessage, InferenceResult } from '@/types/inference';

/**
 * Wrapper around llama.rn's native context. We keep our own opaque shape
 * (`{ id, modelPath, native }`) so callers don't depend on llama.rn's
 * internal class. `native` is the underlying LlamaContext used to call
 * completion / release.
 */
export interface LlamaContext {
  id: number;
  modelPath: string;
  native: NativeLlamaContext;
}

export interface InitOptions {
  /** Absolute path to the main GGUF file on device. */
  model: string;
  /** Reserved for multimodal — unused this milestone. */
  mmproj?: string;
  /** KV cache size in tokens. Default 2048 — conservative for 8 GB phones. */
  contextSize?: number;
  /** CPU thread count for inference. Default 4. */
  threadCount?: number;
}

export interface CompletionParams {
  messages: InferenceMessage[];
}

export type TokenCallback = (token: string) => void;

/**
 * Test-only switch. Set `__forceError.value = true` to make initLlama or
 * completion throw, exercising the chat error path without needing the
 * real model.
 */
export const __forceError = { value: false };

/** Stop tokens for Gemma chat template + a safety net for other tags. */
const STOP_TOKENS = ['<end_of_turn>', '<|end_of_turn|>', '<eos>', '</s>', '<|endoftext|>'] as const;

const STOP_TOKEN_SET = new Set<string>(STOP_TOKENS);

export async function initLlama(options: InitOptions): Promise<LlamaContext> {
  if (__forceError.value) {
    throw new Error('Couldn’t load Antoine. Check the model files in Settings.');
  }
  const native = await nativeInitLlama({
    model: options.model,
    n_ctx: options.contextSize ?? 2048,
    n_threads: options.threadCount ?? 4,
    n_gpu_layers: 0,
  });
  return { id: native.id, modelPath: options.model, native };
}

export async function completion(
  ctx: LlamaContext,
  params: CompletionParams,
  onToken?: TokenCallback,
): Promise<InferenceResult> {
  if (__forceError.value) {
    throw new Error('Antoine stalled. Try the question again.');
  }
  const result = await ctx.native.completion(
    {
      messages: params.messages,
      n_predict: 1024,
      temperature: 0.7,
      top_p: 0.9,
      stop: [...STOP_TOKENS],
    },
    onToken
      ? (data: TokenData) => {
          const t = data.token ?? '';
          if (!t) return;
          if (STOP_TOKEN_SET.has(t)) return;
          onToken(t);
        }
      : undefined,
  );
  return { text: result.text ?? '', tokensUsed: result.timings?.predicted_n };
}

export async function releaseAllLlama(): Promise<void> {
  await nativeReleaseAll();
}

export function buildMessageArray(history: InferenceMessage[]): InferenceMessage[] {
  return [{ role: 'system', content: ANTOINE_SYSTEM_PROMPT }, ...history];
}
